CREATE VIEW "dbo"."OSCDocuments" AS SELECT OPF.OSCProfileHasFileId AS Id, OP.Name AS OSC, FT.name AS Documento, FC.Name AS Categoría, FS.Description AS Estatus FROM "dbo"."OSCProfileHasFile" AS OPF INNER JOIN OSCProfile AS OP ON OPF.OSCProfileId = OP.OSCProfileId INNER JOIN Status AS FS ON OPF.FileStatusId = FS.StatusId INNER JOIN FileType AS FT ON OPF.FileTypeId = FT.FileTypeId INNER JOIN FileCategory AS FC ON FT.FileCategoryId = FC.FileCategoryId WHERE NOT OPF."OSCProfileId" IS NULL AND OPF.StatusId = 1;
